import React from 'react';
import '../styles/components/Experience.css';

function Experience() {
  const experiences = [
    {
      type: 'Organisasi',
      title: 'Ketua Divisi IT',
      organization: 'Himpunan Mahasiswa',
      period: '2024 - Present',
      description: 'Memimpin tim IT dalam pengembangan sistem dan infrastruktur teknologi organisasi.'
    },
    {
      type: 'Kepanitiaan',
      title: 'Koordinator Acara',
      organization: 'Seminar Nasional Tech 2024',
      period: '2024',
      description: 'Mengkoordinir 50+ panitia dalam pelaksanaan seminar dengan 500+ peserta.'
    },
    {
      type: 'Organisasi',
      title: 'Staff Divisi Media',
      organization: 'BEM Fakultas',
      period: '2023 - 2024',
      description: 'Mengelola konten media sosial dan dokumentasi kegiatan organisasi.'
    },
    {
      type: 'Kepanitiaan',
      title: 'Sie Publikasi',
      organization: 'Workshop Programming',
      period: '2023',
      description: 'Bertanggung jawab dalam promosi dan publikasi event workshop.'
    }
  ];

  return (
    <section id="experience" className="experience">
      <div className="container">
        <h2 className="section-title">Experience</h2>
        <div className="experience-timeline">
          {experiences.map((exp, index) => (
            <div key={index} className="timeline-item">
              <div className="timeline-badge">{exp.type}</div>
              <div className="timeline-content">
                <h3>{exp.title}</h3>
                <h4>{exp.organization}</h4>
                <span className="period">{exp.period}</span>
                <p>{exp.description}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Experience;
